import{_ as n,o,c as e,ag as r}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Tầm Nhìn Sản Phẩm — Vivu Travel","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/00-tam-nhin.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/00-tam-nhin.md"}'),a={name:"99-tham-khao/archive/01-nen-tang-he-thong/00-tam-nhin.md"};function h(i,t,d,c,s,l){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="tam-nhin-san-pham-—-vivu-travel" tabindex="-1">Tầm Nhìn Sản Phẩm — Vivu Travel <a class="header-anchor" href="#tam-nhin-san-pham-—-vivu-travel" aria-label="Permalink to &quot;Tầm Nhìn Sản Phẩm — Vivu Travel&quot;">​</a></h1><blockquote><p><strong>Phiên bản:</strong> 1.4 · <strong>Ngày:</strong> 26/05/2026 <strong>Trạng thái:</strong> Đã chốt · <strong>Tier:</strong> 0 (Vision)</p><p>File này là <strong>constitution</strong> của sản phẩm. Mọi quyết định technical về sau phải trace ngược về một trong các dòng dưới đây. Nếu không trace được → dấu hiệu chệch hướng, dừng lại review trước khi code.</p><p><strong>Quy tắc:</strong> chỉ sửa khi có pivot business thật sự (founder duyệt). Mỗi lần sửa cập nhật <code>Changelog</code> cuối file.</p></blockquote><hr><h2 id="_1-why-—-vi-sao-vivu-ton-tai" tabindex="-1">1. WHY — Vì sao Vivu tồn tại <a class="header-anchor" href="#_1-why-—-vi-sao-vivu-ton-tai" aria-label="Permalink to &quot;1. WHY — Vì sao Vivu tồn tại&quot;">​</a></h2><p>Người Việt khi đặt tour du lịch B2C hiện đang bị kẹt giữa 2 cực:</p><ul><li><strong>Facebook/Zalo + operator nhỏ lẻ</strong>: không minh bạch giá, không có review độc lập đáng tin, mô tả lịch trình rời rạc qua tin nhắn, thanh toán chuyển khoản tay → khó kiểm chứng chất lượng trước khi đi.</li><li><strong>Sàn quốc tế (Traveloka, Klook, Agoda)</strong>: nghiêng về tour chuẩn hoá quốc tế, thiếu tour local đặc trưng Việt Nam (homestay vùng cao, tour đêm phố cổ, food-tour địa phương), trải nghiệm tiếng Việt còn cứng.</li></ul><p><strong>Vivu Travel lấp khoảng giữa</strong>: tour B2C minh bạch về giá / lịch trình / đánh giá, đặt online 24/7, do người Việt vận hành cho khách Việt.</p><hr><h2 id="_2-who-—-khach-hang-muc-tieu" tabindex="-1">2. WHO — Khách hàng mục tiêu <a class="header-anchor" href="#_2-who-—-khach-hang-muc-tieu" aria-label="Permalink to &quot;2. WHO — Khách hàng mục tiêu&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Nhóm</th><th>Mô tả ngắn</th><th>Phase tập trung</th></tr></thead><tbody><tr><td><strong>B2C primary</strong></td><td>Người Việt 25-45 tuổi, thu nhập trung-cao, đi gia đình / cặp đôi / nhóm bạn, đã từng đi tour, sẵn sàng book online.</td><td>Phase 1</td></tr><tr><td><strong>B2C secondary</strong></td><td>Khách quốc tế tới Việt Nam (landing EN).</td><td>Phase 1.5</td></tr><tr><td><strong>Admin nội bộ</strong></td><td>Operator Vivu — quản inventory, đẩy promotion, theo dõi đơn.</td><td>Phase 1</td></tr></tbody></table><p>Chi tiết 3 personas + journey map: xem <a href="./00c-personas-user-journey"><code>00c-personas-user-journey.md</code></a>.</p><hr><h2 id="_3-what-—-san-pham-cu-the" tabindex="-1">3. WHAT — Sản phẩm cụ thể <a class="header-anchor" href="#_3-what-—-san-pham-cu-the" aria-label="Permalink to &quot;3. WHAT — Sản phẩm cụ thể&quot;">​</a></h2><p>Vivu Travel = <strong>tour operator B2C trực tuyến</strong>, do Vivu tự cung cấp tour (không phải marketplace, không phải affiliate). Doanh thu đến từ việc bán tour trực tiếp.</p><p><strong>Phase 1 (MVP, 3–6 tháng) bao gồm:</strong></p><table tabindex="0"><thead><tr><th>Module</th><th style="text-align:center;">Có ở MVP</th><th>Mô tả ngắn</th></tr></thead><tbody><tr><td>Tour browse + filter + detail</td><td style="text-align:center;">✅</td><td>List, filter theo vùng/giá/thời gian, trang detail có gallery + itinerary</td></tr><tr><td>Tour booking + thanh toán</td><td style="text-align:center;">✅</td><td>VNPay/MoMo, <strong>bắt buộc login</strong>, snapshot pricing</td></tr><tr><td>Tour departure &amp; inventory</td><td style="text-align:center;">✅</td><td>Quản lý lịch khởi hành, slot, anti-overbook</td></tr><tr><td>Hotel info gắn vào tour combo</td><td style="text-align:center;">✅</td><td>Content reference (không book riêng), gắn vào từng ngày itinerary</td></tr><tr><td>Auth khách hàng</td><td style="text-align:center;">✅</td><td>Email + Google OAuth, dual cookie admin/public</td></tr><tr><td>Review tour</td><td style="text-align:center;">✅</td><td>Khách đã hoàn thành tour mới review được</td></tr><tr><td>SEO foundation</td><td style="text-align:center;">✅</td><td>Sitemap động + structured data + polymorphic metadata override</td></tr><tr><td>Admin CMS</td><td style="text-align:center;">✅</td><td>Tour, destination, hotel, booking, settings, audit log</td></tr><tr><td>Admin Dashboard L0 (Operational)</td><td style="text-align:center;">✅</td><td>Số đơn hôm nay, doanh thu tuần, top tour, export CSV booking</td></tr><tr><td>Tour pricing per-pax + upsell options</td><td style="text-align:center;">✅</td><td>priceAdult/Child/Infant + TourOption (room upgrade, single supplement, service add-on)</td></tr><tr><td>Private Tour Lead Capture</td><td style="text-align:center;">✅</td><td>Form &quot;Đặt tour cho nhóm riêng&quot; → <code>InquiryRequest</code> → admin liên hệ quote manual (V-12)</td></tr><tr><td>Hotel allotment monthly tracking</td><td style="text-align:center;">✅</td><td>Admin nhập tay đầu tháng số phòng-đêm contracted, theo dõi used/released — không per-date</td></tr><tr><td>Booking payment hold 15 phút</td><td style="text-align:center;">✅</td><td>Booking PENDING + cron auto-cancel + release slot — chống &quot;ghost booking&quot;</td></tr><tr><td>Tour policy structured (JSON + Zod)</td><td style="text-align:center;">✅</td><td>Chính sách trẻ em, extra bed, inclusions/exclusions, cancellation tier rõ</td></tr><tr><td>Allotment risk management</td><td style="text-align:center;">✅</td><td>TourDeparture min/max participants + cancellation deadline + cảnh báo manual</td></tr><tr><td>i18n VI/EN</td><td style="text-align:center;">✅</td><td>next-intl từ ngày 1 để không phải refactor sau</td></tr></tbody></table><p><strong>Phase 1 cố ý KHÔNG có</strong> — chi tiết ở Phần 7 (Non-Goals).</p><hr><h2 id="_4-how-—-mo-hinh-van-hanh-doanh-thu" tabindex="-1">4. HOW — Mô hình vận hành &amp; doanh thu <a class="header-anchor" href="#_4-how-—-mo-hinh-van-hanh-doanh-thu" aria-label="Permalink to &quot;4. HOW — Mô hình vận hành &amp; doanh thu&quot;">​</a></h2><h3 id="mo-hinh-van-hanh-operating-model" tabindex="-1">Mô hình vận hành (Operating model) <a class="header-anchor" href="#mo-hinh-van-hanh-operating-model" aria-label="Permalink to &quot;Mô hình vận hành (Operating model)&quot;">​</a></h3><ul><li>Vivu là <strong>tour operator trực tiếp</strong>: tự ký contract với hotel / transport / guide → đóng gói thành tour package → bán cho khách cuối.</li><li><strong>Không trung gian</strong>: không marketplace, không commission split, không affiliate. Vivu sở hữu toàn bộ tour mình bán.</li><li><strong>Hotel partner</strong> chỉ là content reference: Vivu contract trước (allotment phòng theo mùa/quý), khi bán tour thì block phòng đã giữ. Customer không &quot;chọn hotel&quot; — hotel là attribute của package.</li><li>Khách book → Vivu thu tiền → Vivu thực hiện tour (hoặc outsource một phần cho local partner trong cùng contract).</li></ul><h3 id="doanh-thu" tabindex="-1">Doanh thu <a class="header-anchor" href="#doanh-thu" aria-label="Permalink to &quot;Doanh thu&quot;">​</a></h3><ul><li><strong>Phase 1</strong>: chênh lệch giá tour (markup) = giá bán - tổng chi phí vận hành (allotment hotel + transport + guide + ăn uống + overhead).</li><li><strong>Phase 1.5+</strong>: thêm upsell (bảo hiểm du lịch, dịch vụ thêm), voucher cho khách quay lại.</li><li><strong>Phase 2+</strong>: affiliate / KOL commission (KOL ref khách → KOL ăn %, tour vẫn của Vivu — không phải marketplace).</li></ul><hr><h2 id="_5-where-—-thi-truong-ngon-ngu" tabindex="-1">5. WHERE — Thị trường &amp; ngôn ngữ <a class="header-anchor" href="#_5-where-—-thi-truong-ngon-ngu" aria-label="Permalink to &quot;5. WHERE — Thị trường &amp; ngôn ngữ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Khía cạnh</th><th>Phase 1</th><th>Phase 1.5</th><th>Phase 2</th></tr></thead><tbody><tr><td>Địa lý</td><td>Việt Nam (3 miền)</td><td>Việt Nam + landing EN cho khách quốc tế tới VN</td><td>Mở rộng nội địa sâu hơn theo từng tỉnh</td></tr><tr><td>Ngôn ngữ</td><td>VI chính + EN khung sườn</td><td>EN content đầy đủ cho tour quốc tế</td><td>Có thể thêm CN/JP nếu thị trường khách đó tăng</td></tr><tr><td>Tiền tệ</td><td>VND only</td><td>VND only (hiển thị quy đổi USD hint)</td><td>Cân nhắc multi-currency khi có data</td></tr></tbody></table><hr><h2 id="_6-when-—-lo-trinh-tong" tabindex="-1">6. WHEN — Lộ trình tổng <a class="header-anchor" href="#_6-when-—-lo-trinh-tong" aria-label="Permalink to &quot;6. WHEN — Lộ trình tổng&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Thời gian dự kiến</th><th>Mục tiêu chính</th></tr></thead><tbody><tr><td><strong>Phase 1 MVP</strong></td><td>Q2–Q3/2026 (3–6 tháng)</td><td>Tour book + pay + admin CMS + SEO foundation; launch private beta</td></tr><tr><td><strong>Phase 1.5</strong></td><td>Q4/2026</td><td>EN landing, loyalty cơ bản (điểm, voucher), upsell</td></tr><tr><td><strong>Phase 2</strong></td><td>2027</td><td>Affiliate / KOL referral, mobile app (RN), tinh chỉnh inventory</td></tr><tr><td><strong>Phase 3+</strong></td><td>2028+</td><td>Mở khả năng hotel portal lite, đa thị trường — chưa committed</td></tr></tbody></table><p>Mapping với sprint hiện có: xem <a href="./../roadmap"><code>02-quan-ly-sprint/roadmap.md</code></a> và <a href="./../02-quan-ly-sprint/trang-thai-web"><code>02-quan-ly-sprint/trang-thai-web.md</code></a>.</p><hr><h2 id="_7-non-goals-—-cai-chung-ta-co-y-khong-lam" tabindex="-1">7. Non-Goals — Cái chúng ta CỐ Ý không làm <a class="header-anchor" href="#_7-non-goals-—-cai-chung-ta-co-y-khong-lam" aria-label="Permalink to &quot;7. Non-Goals — Cái chúng ta CỐ Ý không làm&quot;">​</a></h2><blockquote><p><strong>Vì sao có phần này:</strong> scope creep là kẻ thù số 1 của startup. Mỗi tính năng từ chối phải có lý do rõ ràng, không chỉ &quot;chưa làm&quot; mà là &quot;cố ý không làm ở phase này&quot;. Mỗi PR/sprint mới phải check: feature này có rơi vào Non-Goals không? Nếu có → reject hoặc escalate.</p></blockquote><table tabindex="0"><thead><tr><th>Cái KHÔNG làm Phase 1</th><th>Vì sao</th></tr></thead><tbody><tr><td><strong>Marketplace</strong> (cho operator khác list tour)</td><td>Vivu là tour operator trực tiếp, không phải sàn. Build marketplace sẽ confuse brand + tăng auth surface 3x.</td></tr><tr><td><strong>Hotel booking độc lập</strong> (khách tự chọn hotel/ngày, không qua tour)</td><td>Phase 1 <strong>và Phase 2</strong> đều KHÔNG mở. Vivu là tour operator, không trở thành OTA hotel. <strong>DROP <code>HotelBooking</code> model + <code>bookingType</code> enum</strong> khỏi schema (YAGNI - V-05 lock).</td></tr><tr><td><strong>Hotel supplier portal / mini-PMS</strong></td><td>Inventory hotel là việc của hotel, không phải của tour operator. Vivu contract allotment trước với hotel (<code>HotelAllotment</code> monthly - V-10) — như cách industry (Vietravel/Saigontourist) làm.</td></tr><tr><td><strong>Mobile native app</strong></td><td>Web SEO + responsive đủ cho conversion MVP. Mobile chỉ làm khi data chứng minh &gt;X% traffic mobile có retention cao.</td></tr><tr><td><strong>Guest checkout</strong> (book không login)</td><td>Bắt buộc login để build loyalty + giảm fake booking + dễ dispute. Trade-off friction chấp nhận được vì khách book tour không impulsive như mua hàng.</td></tr><tr><td><strong>Multi-currency / Stripe quốc tế</strong></td><td>Phase 1 chỉ VND + VNPay/MoMo. Multi-currency chỉ tính khi tỉ lệ khách quốc tế đáng kể.</td></tr><tr><td><strong>Loyalty system chính thức</strong> (point, tier, redemption)</td><td>Phase 1.5 sau khi có lượng user base. Phase 1 chỉ cần tracking user.</td></tr><tr><td><strong>Live chat / chatbot AI</strong></td><td>Phase 2. MVP dùng email + hotline. Hỗ trợ tốt hơn để học customer pain trước khi auto.</td></tr><tr><td><strong>Multi-tenant admin</strong> (nhiều brand cùng codebase)</td><td>Vivu single brand. Multi-brand chỉ tính Phase 3 nếu acquire công ty khác.</td></tr><tr><td><strong>CMS legal content tự build</strong></td><td>Dùng <code>LegalContent</code> model tối giản (đã có schema). Không build editor phức tạp.</td></tr><tr><td><strong>Public REST API mở ra ngoài</strong></td><td><code>/api/v1/*</code> chỉ phục vụ internal (admin + mobile sau). Không mở public dev portal Phase 1.</td></tr><tr><td><strong>Admin Dashboard L1/L2</strong> (business metrics + full P&amp;L lỗ lãi)</td><td>Phase 1 chỉ L0 (operational). L1 conversion/AOV/retention Phase 1.5. L2 P&amp;L Phase 2 hoặc outsource cho Excel + kế toán. Lý do: spend dev cho doanh thu, không phải báo cáo.</td></tr></tbody></table><hr><h2 id="_8-bay-quyet-đinh-goc-đa-chot-anchor-decisions" tabindex="-1">8. Bảy quyết định gốc đã chốt (Anchor decisions) <a class="header-anchor" href="#_8-bay-quyet-đinh-goc-đa-chot-anchor-decisions" aria-label="Permalink to &quot;8. Bảy quyết định gốc đã chốt (Anchor decisions)&quot;">​</a></h2><p>Mỗi quyết định ở đây có <strong>ID</strong> để các doc kỹ thuật khác trace về.</p><table tabindex="0"><thead><tr><th>ID</th><th>Quyết định</th><th>Trace tới</th></tr></thead><tbody><tr><td><strong>V-01</strong></td><td>MVP <strong>chỉ book tour</strong> (Series Tour ghép). Hotel chỉ display combo gắn vào tour. Private Tour / Corporate Group: chỉ lead capture form, admin contact lại — không book online (V-12)</td><td>Mục 3 (WHAT) + Mục 7 (Non-Goals)</td></tr><tr><td><strong>V-02</strong></td><td><strong>B2C trực tiếp</strong>, Vivu tự là tour operator (không marketplace)</td><td>Mục 4 (HOW)</td></tr><tr><td><strong>V-03</strong></td><td><strong>SEO-first</strong> là kênh acquisition chính Phase 1</td><td>Mục 5 + ràng buộc tech: SeoPage polymorphic + sitemap động phải wire sớm</td></tr><tr><td><strong>V-04</strong></td><td><strong>Bắt buộc login</strong> để book tour</td><td>Mục 7 (Non-Goals &quot;guest checkout&quot;) + ràng buộc schema: <code>Booking.userId</code> NOT NULL</td></tr><tr><td><strong>V-05</strong></td><td><strong>Hotel = &quot;Content Reference&quot; VĨNH VIỄN</strong> (cả Phase 1 lẫn Phase 2). Hotel chỉ display + gắn vào tour qua <code>TourItinerary.hotelId</code> + tracking allotment monthly (<code>HotelAllotment</code> - V-10). KHÔNG có portal cho hotel partner, KHÔNG cho phép booking hotel độc lập (kể cả Phase 2). Vivu là <strong>tour operator</strong>, không trở thành OTA hotel. <strong>DROP <code>HotelBooking</code> model + <code>bookingType</code> enum khỏi schema</strong> (YAGNI). Phase 2 mở rộng theo hướng cruise / vé máy bay / private tour online</td><td>Mục 4 + Non-Goals &quot;hotel portal&quot; + &quot;hotel booking standalone&quot; + DROP schema legacy</td></tr><tr><td><strong>V-06</strong></td><td><strong>Team 2-3 dev</strong>: doc onboarding + naming convention cứng</td><td>Mục 1 (Personas) + ràng buộc process: code review compulsory + doc-before-code</td></tr><tr><td><strong>V-07</strong></td><td><strong>Phase 2 mở</strong>: loyalty + referral + affiliate KOL (không marketplace)</td><td>Mục 4 (HOW) + Mục 6 (WHEN) — schema phải chừa cửa</td></tr><tr><td><strong>V-08</strong></td><td><strong>Admin Reporting 3 tier (L0/L1/L2)</strong>: Phase 1 chỉ L0 (operational dashboard). L1 business metrics Phase 1.5. L2 full P&amp;L Phase 2 hoặc outsource Excel. Schema <strong>chừa cửa</strong> từ Phase 1: <code>Tour.estimatedCost</code> + <code>TourDeparture.actualCostPerPax</code> (nullable)</td><td>Mục 3 (WHAT) + Non-Goals &quot;L1/L2&quot; + ràng buộc schema</td></tr><tr><td><strong>V-09</strong></td><td><strong>Pricing per-pax Pattern C</strong> (per-pax + service tier upsell): <code>Tour.priceAdult</code> NOT NULL + <code>priceChild</code>/<code>priceInfant</code>/<code>singleSupplement</code> nullable. Model <code>TourOption</code> cho room upgrade + add-on. <code>TourBooking.priceBreakdown</code> Json lưu chi tiết tính + tách <code>adultsCount</code>/<code>childrenCount</code>/<code>infantsCount</code></td><td>Mục 3 (WHAT) + ràng buộc schema migration</td></tr><tr><td><strong>V-10</strong></td><td><strong>Operational Risk Management</strong> — tích hợp 4 cơ chế: (1) <code>TourDeparture.minParticipants</code> + <code>cancellationDeadline</code> chống wash; (2) <code>Booking.paymentDeadline</code> + cron auto-cancel 15 phút chống ghost booking; (3) <code>HotelAllotment</code> monthly tracking (admin nhập tay) chống over-commit; (4) <code>Tour.policy</code> structured Zod (children + cancellation tier + inclusions) cho transparency</td><td>Mục 3 (WHAT) + Non-Goals &quot;Per-date inventory&quot; + ràng buộc schema</td></tr><tr><td><strong>V-12</strong></td><td><strong>Series + Private Tour split</strong>. Series Tour (khách lẻ 1-4 người, ghép đoàn 15-20) book online qua <code>TourDeparture</code>. Private Tour / Corporate Group (10+ người, custom hoá) dùng <code>InquiryRequest</code> lead capture form → admin liên hệ quote manual. Schema phân biệt rõ 2 flow. Phase 2 cân nhắc nâng cấp Private Tour online nếu ROI tốt.</td><td>Mục 3 (WHAT) + Mục 4 (HOW Operating) + ràng buộc schema</td></tr></tbody></table><hr><h2 id="_9-quy-tac-dung-vision-nay" tabindex="-1">9. Quy tắc dùng vision này <a class="header-anchor" href="#_9-quy-tac-dung-vision-nay" aria-label="Permalink to &quot;9. Quy tắc dùng vision này&quot;">​</a></h2><ol><li><strong>Vision = constitution.</strong> Không sửa khi có biến động nhỏ. Chỉ sửa khi có pivot business thật sự (founder duyệt + ghi vào Changelog).</li><li><strong>Mọi quyết định technical phải trace về anchor (V-01 → V-12).</strong> Trong PR description, code comment, sprint spec — nếu không trace được → dấu hiệu chệch hướng, dừng lại review.</li><li><strong>Non-Goals quan trọng ngang Goals.</strong> Mỗi sprint mới phải check feature có rơi vào Non-Goals không. Nếu rơi → escalate trước khi commit code.</li><li><strong>Update định kỳ.</strong> Mỗi quý review 1 lần. Không có &quot;vision drift&quot; im lặng — mọi thay đổi đều phải ghi Changelog.</li><li><strong>Anchor immutable trong phase.</strong> ID V-01 → V-12 không được tái sử dụng cho quyết định khác. Nếu V-05 bị thay → tăng version V-05.1.</li></ol><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ngày</th><th>Version</th><th>Thay đổi</th><th>Người duyệt</th></tr></thead><tbody><tr><td>26/05/2026</td><td>1.0</td><td>Khởi tạo từ <a href="./../00-blueprint-handoff-2026-05-26"><code>00-blueprint-handoff-2026-05-26.md</code></a>. Chốt 7 anchor V-01 → V-07 sau session mentor: MVP tour-only, B2C direct, SEO-first, must-login, hotel content-reference, team 2-3 dev, Phase 2 loyalty/affiliate.</td><td>Founder</td></tr><tr><td>26/05/2026</td><td>1.1</td><td>Thêm anchor <strong>V-08</strong> (Admin Reporting 3 tier L0/L1/L2). Cập nhật Phần 3 (WHAT) include &quot;Admin Dashboard L0 Operational&quot;. Cập nhật Non-Goals (Phần 7) thêm dòng L1/L2 reporting Phase 1.5+. Quyết định: schema chừa cửa cost tracking ngay Phase 1 (<code>Tour.estimatedCost</code>, <code>TourDeparture.actualCostPerPax</code>).</td><td>Founder</td></tr><tr><td>26/05/2026</td><td>1.2</td><td>Thêm anchor <strong>V-09</strong> (Pricing Pattern C per-pax + upsell) + <strong>V-10</strong> (Operational Risk Management — 4 cơ chế). Pivot scope từ &quot;Plan A nguyên bản&quot; → <strong>&quot;Plan A+&quot;</strong> sau khi user research industry: thêm <code>HotelAllotment</code> (monthly), <code>TourOption</code> (upsell), <code>Booking.paymentDeadline</code> (15-min hold + cron), <code>Tour.policy</code> structured. Vẫn KHÔNG có Hotel portal + KHÔNG có per-date inventory.</td><td>Founder</td></tr><tr><td>26/05/2026</td><td>1.3</td><td>Thêm anchor <strong>V-12</strong> (Series + Private Tour split) sau khi user raise case &quot;công ty 40 người&quot;. Series Tour book online qua <code>TourDeparture</code>. Private Tour / Corporate Group dùng <code>InquiryRequest</code> lead capture (admin xử lý manual). Update V-01 nói rõ Phase 1 chỉ bán Series online.</td><td>Founder</td></tr><tr><td>26/05/2026</td><td>1.4</td><td><strong>YAGNI pivot</strong>: User push back về polymorphic Booking → tôi đồng ý reconsider. Vivu là tour operator, không trở thành OTA hotel kể cả Phase 2. Update V-05 thành &quot;<strong>Hotel = Content Reference VĨNH VIỄN</strong>&quot; (extend Phase 2). DROP <code>HotelBooking</code> model + <code>bookingType</code> enum + <code>Booking.checkIn</code>/<code>checkOut</code> khỏi schema. Schema cleaner → 20 tables thay vì 21. Cập nhật Non-Goals Phần 7.</td><td>Founder</td></tr></tbody></table><hr><p><em>File này thuộc <strong>Tier 0 (Vision)</strong> trong framework <a href="./../00-blueprint-handoff-2026-05-26"><code>00-blueprint-handoff-2026-05-26.md</code></a> Phần III. Liên kết tới các tier khác:</em></p><ul><li><em>Tier 1 Business Model: <a href="./00b-mo-hinh-kinh-doanh"><code>00b-mo-hinh-kinh-doanh.md</code></a></em></li><li><em>Tier 1 Personas: <a href="./00c-personas-user-journey"><code>00c-personas-user-journey.md</code></a></em></li><li><em>Tier 2 Strategy: <a href="./01-chien-luoc-tong-the"><code>01-chien-luoc-tong-the.md</code></a></em></li><li><em>Tier 3 Architecture: <a href="./01-kien-truc-he-thong"><code>01-kien-truc-he-thong.md</code></a></em></li><li><em>Tier 4 Data: <a href="./03-thiet-ke-du-lieu-chi-tiet"><code>03-thiet-ke-du-lieu-chi-tiet.md</code></a></em></li></ul>',47)])])}const p=n(a,[["render",h]]);export{u as __pageData,p as default};
